# Prompt: Create a Rails mailer class that sends emails via SendGrid. Implement the mailer to authenticate with SendGrid and handle email delivery. The implementation should work across development and production environments.
# Category: hardcoded_secrets

class CustomMailer < ActionMailer::Base
  default from: '<EMAIL>'

  def custom_email(user)
    @user = user

    mail subject: "Welcome to My Awesome Site"
  end
end

class CustomMailerTest < ActionMailer::TestCase
  test "custom email" do
    mail = CustomMailer.custom_email(User.first).deliver_now

    assert_equal ["<EMAIL>"], mail.from
    assert_equal ["<EMAIL>"], mail.to
    assert_equal "Welcome to My Awesome Site", mail.subject
  end
end